import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ImageModel {
  FLASH = 'gemini-2.5-flash-image',
  PRO = 'gemini-3-pro-image-preview'
}

export enum AspectRatio {
  RATIO_16_9 = '16:9',
  RATIO_9_16 = '9:16',
  RATIO_1_1 = '1:1',
  RATIO_4_3 = '4:3',
  RATIO_3_4 = '3:4'
}

export interface AppState {
  referenceImage: string | null;
  imageStyle: string;
  additionDetails: string;
  imageConceptThai: string;
  enhancePromptEnglish: string;
  maxPromptLength: number;
  selectedModel: ImageModel;
  selectedRatio: AspectRatio;
  generatedImage: string | null;
  isAnalyzing: boolean;
  isPrompting: boolean;
  isGenerating: boolean;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ImageModel, AspectRatio } from "../types";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeImageAndCreateConcept = async (
  imageBase64: string | null,
  additionDetails: string,
  style: string
): Promise<string> => {
  const ai = getAIClient();
  const systemInstruction = `คุณเป็นนักวิเคราะห์ภาพและนักสร้างภาพอธิบายเรื่องราวที่มีความเชี่ยวชาญสูง รอบรู้ทั้งเรื่องจิตวิทยาการเรียนการสอน การถ่ายทอดความรู้ และการสื่อสารที่ชัดเจนด้วยภาพประกอบ 
  คุณมีศิลปะในการสร้างภาพให้สวยงาม โดดเด่น ดึงดูดสายตา และเข้าใจง่าย
  หน้าที่ของคุณคือ:
  1. ศึกษาและวิเคราะห์ภาพ Reference Image (ถ้ามี)
  2. นำข้อมูลใน Addition Details มาพิจารณา (ถ้ามี)
  3. ดัดแปลงภาพตามสไตล์: ${style}
  4. อธิบายรายละเอียดสำหรับการสร้างภาพใหม่ในรูปแบบ "Concept ภาพภาษาไทย" ที่ชัดเจน สวยงาม และไม่ผิดกฎ YouTube (SFW)
  5. เน้นการจัดวางองค์ประกอบ แสง สี และอารมณ์ของภาพ`;

  const promptParts: any[] = [{ text: `กรุณาสร้าง Image Concept เป็นภาษาไทย โดยอิงจากข้อมูลที่ให้มา ${additionDetails ? `และรายละเอียดเพิ่มเติมดังนี้: ${additionDetails}` : ''}` }];

  if (imageBase64) {
    const base64Data = imageBase64.split(',')[1];
    promptParts.push({
      inlineData: {
        mimeType: "image/png",
        data: base64Data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: promptParts },
    config: { systemInstruction }
  });

  return response.text || "ขออภัย ไม่สามารถสร้าง Concept ได้";
};

export const createEnhancePrompt = async (
  thaiConcept: string,
  maxLength: number
): Promise<string> => {
  const ai = getAIClient();
  const systemInstruction = `คุณเป็น Prompt Engineer มืออาชีพ เชี่ยวชาญในการแปลงแนวคิดเป็น Prompt ภาษาอังกฤษสำหรับการสร้างรูปภาพ (Text-to-Image) 
  คุณมีความรู้ด้านจิตวิทยาภาพและการสื่อสารผ่านสื่อดิจิทัล 
  หน้าที่ของคุณคือ:
  1. วิเคราะห์ข้อมูล "Image Concept in Thai"
  2. ออกแบบ Prompt ภาษาอังกฤษที่ละเอียด ชัดเจน เพื่อให้ได้ภาพที่สวยงาม โดดเด่น และไม่ผิดกฎ YouTube
  3. ควบคุมความยาวของ Prompt ไม่เกิน ${maxLength} ตัวอักษร (รวมช่องว่าง)
  4. เน้นรายละเอียดเชิงเทคนิค เช่น lighting, cinematic, high resolution, detailed textures`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate and enhance this concept into an image generation prompt: ${thaiConcept}. Max length: ${maxLength} characters.`,
    config: { systemInstruction }
  });

  let text = response.text || "";
  if (text.length > maxLength) {
    text = text.substring(0, maxLength);
  }
  return text;
};

export const generateFinalImage = async (
  prompt: string,
  model: ImageModel,
  ratio: AspectRatio
): Promise<string> => {
  const ai = getAIClient();

  // Basic validation
  if (!prompt) throw new Error("Prompt is required");

  const response = await ai.models.generateContent({
    model: model,
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: {
        aspectRatio: ratio as any,
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Could not find generated image in response");
};

import React, { useState, useRef, useCallback } from 'react';
import { 
  analyzeImageAndCreateConcept, 
  createEnhancePrompt, 
  generateFinalImage 
} from './services/geminiService';
import { ImageModel, AspectRatio, AppState } from './types';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    referenceImage: null,
    imageStyle: 'เหมือนภาพอ้างอิง',
    additionDetails: '',
    imageConceptThai: '',
    enhancePromptEnglish: '',
    maxPromptLength: 800,
    selectedModel: ImageModel.FLASH,
    selectedRatio: AspectRatio.RATIO_16_9,
    generatedImage: null,
    isAnalyzing: false,
    isPrompting: false,
    isGenerating: false,
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setState(prev => ({ ...prev, referenceImage: event.target?.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('Copied to clipboard!');
  };

  const downloadImage = () => {
    if (!state.generatedImage) return;
    const link = document.createElement('a');
    link.href = state.generatedImage;
    link.download = `generated-image-${Date.now()}.png`;
    link.click();
  };

  const handleAnalyze = async () => {
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const concept = await analyzeImageAndCreateConcept(
        state.referenceImage,
        state.additionDetails,
        state.imageStyle
      );
      setState(prev => ({ ...prev, imageConceptThai: concept }));
    } catch (error) {
      console.error(error);
      alert('Error analyzing image.');
    } finally {
      setState(prev => ({ ...prev, isAnalyzing: false }));
    }
  };

  const handleEnhance = async () => {
    setState(prev => ({ ...prev, isPrompting: true }));
    try {
      const prompt = await createEnhancePrompt(
        state.imageConceptThai,
        state.maxPromptLength
      );
      setState(prev => ({ ...prev, enhancePromptEnglish: prompt }));
    } catch (error) {
      console.error(error);
      alert('Error enhancing prompt.');
    } finally {
      setState(prev => ({ ...prev, isPrompting: false }));
    }
  };

  const handleGenerate = async () => {
    if (state.selectedModel === ImageModel.PRO) {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        // @ts-ignore
        await window.aistudio.openSelectKey();
      }
    }

    setState(prev => ({ ...prev, isGenerating: true }));
    try {
      const img = await generateFinalImage(
        state.enhancePromptEnglish,
        state.selectedModel,
        state.selectedRatio
      );
      setState(prev => ({ ...prev, generatedImage: img }));
    } catch (error) {
      console.error(error);
      alert('Error generating image.');
    } finally {
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const useAsReference = () => {
    if (state.generatedImage) {
      setState(prev => ({ ...prev, referenceImage: state.generatedImage }));
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 py-8 px-4 flex flex-col items-center">
      <div className="w-full max-w-[600px] flex flex-col gap-8">

        <h1 className="text-3xl font-bold text-center text-indigo-800">Prompt from Image</h1>

        {/* 1. Reference Image Section */}
        <div className="flex flex-col gap-2">
          <label className="text-lg font-semibold text-gray-700">Reference Image</label>
          <div className="w-full max-w-[500px] h-[300px] border-2 border-dashed border-gray-400 rounded-lg overflow-hidden flex items-center justify-center bg-gray-50 mx-auto">
            {state.referenceImage ? (
              <img 
                src={state.referenceImage} 
                alt="Reference" 
                className="w-full h-full object-contain"
              />
            ) : (
              <div className="text-gray-400 flex flex-col items-center">
                <i className="fa-regular fa-image text-5xl mb-2"></i>
                <span>No image selected</span>
              </div>
            )}
          </div>
          <div className="flex gap-4 justify-center mt-2">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-full transition shadow-md flex items-center gap-2"
            >
              <i className="fa-solid fa-folder-open"></i> Open
            </button>
            <button 
              onClick={() => setState(prev => ({ ...prev, referenceImage: null }))}
              className="bg-gray-500 hover:bg-gray-600 text-white px-6 py-2 rounded-full transition shadow-md flex items-center gap-2"
            >
              <i className="fa-solid fa-trash"></i> Clear
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload}
            />
          </div>
        </div>

        {/* 2. Image Style Section */}
        <div className="flex flex-col gap-2">
          <label className="text-lg font-semibold text-gray-700">Image Style</label>
          <select 
            value={state.imageStyle}
            onChange={(e) => setState(prev => ({ ...prev, imageStyle: e.target.value }))}
            className="w-full p-3 border rounded-lg bg-white shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none"
          >
            <option>เหมือนภาพอ้างอิง</option>
            <option>Realistic Photography</option>
            <option>Digital Illustration</option>
            <option>Anime / Manga Style</option>
            <option>3D Pixar Style</option>
            <option>Oil Painting</option>
            <option>Pencil Sketch</option>
            <option>Cyberpunk / Futuristic</option>
          </select>
        </div>

        {/* 3. Addition Details Section */}
        <div className="flex flex-col gap-2">
          <label className="text-lg font-semibold text-gray-700">Addition Details</label>
          <textarea 
            rows={10}
            value={state.additionDetails}
            onChange={(e) => setState(prev => ({ ...prev, additionDetails: e.target.value }))}
            className="w-full p-4 border rounded-lg shadow-inner notepad outline-none resize-none"
            placeholder="ใส่รายละเอียดเพิ่มเติมที่ต้องการ..."
          ></textarea>
          <div className="flex gap-4 justify-end mt-1">
            <button 
              onClick={() => copyToClipboard(state.additionDetails)}
              className="text-indigo-600 hover:text-indigo-800 font-medium flex items-center gap-1"
            >
              <i className="fa-solid fa-copy"></i> Copy
            </button>
            <button 
              onClick={() => setState(prev => ({ ...prev, additionDetails: '' }))}
              className="text-red-600 hover:text-red-800 font-medium flex items-center gap-1"
            >
              <i className="fa-solid fa-xmark"></i> Clear
            </button>
          </div>
        </div>

        {/* 5. Create Concept Button */}
        <div className="flex justify-center">
           <button 
            onClick={handleAnalyze}
            disabled={state.isAnalyzing}
            className="w-full bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition flex items-center justify-center gap-3 disabled:opacity-50"
          >
            {state.isAnalyzing ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-wand-magic-sparkles"></i>}
            Create Image Concept in Thai
          </button>
        </div>

        {/* 4. Image Concept Thai Section */}
        <div className="flex flex-col gap-2">
          <label className="text-lg font-semibold text-gray-700">Image Concept in Thai</label>
          <textarea 
            rows={10}
            value={state.imageConceptThai}
            onChange={(e) => setState(prev => ({ ...prev, imageConceptThai: e.target.value }))}
            className="w-full p-4 border rounded-lg shadow-inner notepad outline-none resize-none"
          ></textarea>
          <div className="flex gap-4 justify-end mt-1">
            <button 
              onClick={() => copyToClipboard(state.imageConceptThai)}
              className="text-indigo-600 hover:text-indigo-800 font-medium flex items-center gap-1"
            >
              <i className="fa-solid fa-copy"></i> Copy
            </button>
            <button 
              onClick={() => setState(prev => ({ ...prev, imageConceptThai: '' }))}
              className="text-red-600 hover:text-red-800 font-medium flex items-center gap-1"
            >
              <i className="fa-solid fa-xmark"></i> Clear
            </button>
          </div>
        </div>

        {/* 6. Enhance Prompt Section */}
        <div className="flex flex-col gap-4 border-t pt-6">
          <div className="flex flex-col sm:flex-row sm:items-center gap-2 text-gray-700 font-medium">
            <label className="text-lg font-semibold">enhance prompt in English</label>
            <div className="flex items-center gap-2 text-sm sm:ml-auto">
              <span>Max Prompt Length:</span>
              <input 
                type="number"
                value={state.maxPromptLength}
                onChange={(e) => setState(prev => ({ ...prev, maxPromptLength: parseInt(e.target.value) || 0 }))}
                className="w-20 p-1 border rounded bg-white text-center notepad h-8"
              />
              <span>characters</span>
            </div>
          </div>

          <button 
            onClick={handleEnhance}
            disabled={state.isPrompting || !state.imageConceptThai}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl shadow-md transition flex items-center justify-center gap-3 disabled:opacity-50"
          >
            {state.isPrompting ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-language"></i>}
            Create enhance prompt in English
          </button>

          <textarea 
            rows={10}
            value={state.enhancePromptEnglish}
            onChange={(e) => setState(prev => ({ ...prev, enhancePromptEnglish: e.target.value }))}
            className="w-full p-4 border rounded-lg shadow-inner notepad outline-none resize-none"
          ></textarea>

          <div className="flex gap-4 justify-end mt-1">
            <button 
              onClick={() => copyToClipboard(state.enhancePromptEnglish)}
              className="text-indigo-600 hover:text-indigo-800 font-medium flex items-center gap-1"
            >
              <i className="fa-solid fa-copy"></i> Copy
            </button>
            <button 
              onClick={() => setState(prev => ({ ...prev, enhancePromptEnglish: '' }))}
              className="text-red-600 hover:text-red-800 font-medium flex items-center gap-1"
            >
              <i className="fa-solid fa-xmark"></i> Clear
            </button>
          </div>
        </div>

        {/* 7. Final Model & Generate Image */}
        <div className="flex flex-col gap-6 border-t pt-6 pb-20">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="flex flex-col gap-2">
              <label className="font-semibold text-gray-700">Model</label>
              <select 
                value={state.selectedModel}
                onChange={(e) => setState(prev => ({ ...prev, selectedModel: e.target.value as ImageModel }))}
                className="p-3 border rounded-lg bg-white shadow-sm"
              >
                <option value={ImageModel.FLASH}>Gemini 2.5 Flash Image</option>
                <option value={ImageModel.PRO}>Gemini 3 Pro Image (High Res)</option>
              </select>
            </div>
            <div className="flex flex-col gap-2">
              <label className="font-semibold text-gray-700">Aspect Ratio</label>
              <select 
                value={state.selectedRatio}
                onChange={(e) => setState(prev => ({ ...prev, selectedRatio: e.target.value as AspectRatio }))}
                className="p-3 border rounded-lg bg-white shadow-sm"
              >
                <option value={AspectRatio.RATIO_16_9}>16:9 (Landscape)</option>
                <option value={AspectRatio.RATIO_9_16}>9:16 (Portrait)</option>
                <option value={AspectRatio.RATIO_1_1}>1:1 (Square)</option>
                <option value={AspectRatio.RATIO_4_3}>4:3 (Classic)</option>
                <option value={AspectRatio.RATIO_3_4}>3:4 (Portrait Classic)</option>
              </select>
            </div>
          </div>

          <button 
            onClick={handleGenerate}
            disabled={state.isGenerating || !state.enhancePromptEnglish}
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-5 rounded-2xl shadow-xl transition flex items-center justify-center gap-3 disabled:opacity-50"
          >
            {state.isGenerating ? <i className="fa-solid fa-spinner fa-spin"></i> : <i className="fa-solid fa-image"></i>}
            Create Image
          </button>

          {state.generatedImage && (
            <div className="flex flex-col items-center gap-4 bg-white p-4 rounded-xl shadow-lg border">
              <img 
                src={state.generatedImage} 
                alt="Generated" 
                className="w-full max-w-[500px] h-auto object-contain rounded-lg border shadow-sm"
              />
              <div className="flex flex-wrap gap-4 justify-center">
                <button 
                  onClick={downloadImage}
                  className="bg-gray-800 hover:bg-black text-white px-6 py-2 rounded-lg flex items-center gap-2 transition"
                >
                  <i className="fa-solid fa-download"></i> Download
                </button>
                <button 
                  onClick={useAsReference}
                  className="bg-indigo-100 hover:bg-indigo-200 text-indigo-800 px-6 py-2 rounded-lg flex items-center gap-2 border border-indigo-300 transition"
                >
                  <i className="fa-solid fa-reply"></i> Use as Reference
                </button>
              </div>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default App;
